
#ifndef BC_SCOPEDPOINTER_H_INCLUDED__
#define BC_SCOPEDPOINTER_H_INCLUDED__
#include <BC/Exports.h>

///////////////////////////////////////////////////////////////////////////////
// Namespace : BC
///////////////////////////////////////////////////////////////////////////////

namespace BC
{

///////////////////////////////////////////////////////////////////////////////
/// class : ScopedPointer
///
/// a scoped pointer class to treat heap ptrs
/// like stack ones
///
///////////////////////////////////////////////////////////////////////////////
template<class T>
class ScopedPointer
{
public:
	ScopedPointer(T* t) : pT(t){}
	virtual ~ScopedPointer(){ BC_SAFE_DELETE_PTR(pT); }
	T* Get(){ return pT; }
	const T* Get() const{ return pT; }
	T* operator ->(){ return Get(); }
	const T* operator ->() const{ return Get(); }
	bool IsNull() const{ return Get() == 0; }
	/// the owned pointer is released and
	/// is no longer deleted on exit
	T* Release(){ T* t = pT; pT = 0; return t; }
private:
	T* pT;
	DECLARE_NO_COPY_CLASS(ScopedPointer);
};

///////////////////////////////////////////////////////////////////////////////
// End of namespace : BC
///////////////////////////////////////////////////////////////////////////////

} // End of namespace BC

#endif // BC_SCOPEDPOINTER_H_INCLUDED__

///////////////////////////////////////////////////////////////////////////////
// End of file. 
